package com.example.woofie.ui

import android.content.Context
import android.os.Bundle
import android.view.View
import android.view.animation.AnimationUtils
import android.widget.RadioButton
import android.widget.RadioGroup
import android.widget.TextView
import androidx.fragment.app.Fragment
import com.example.woofie.R
import com.example.woofie.data.WoofieRepository
import com.example.woofie.model.QuizQuestion
import com.google.android.material.button.MaterialButton

class LessonFragment : Fragment(R.layout.fragment_lesson) {

    interface Listener {
        fun onLessonFinished(correctAnswers: Int, totalAnswers: Int)
    }

    private var listener: Listener? = null
    private var questions: List<QuizQuestion> = emptyList()
    private var currentIndex = 0
    private var correctAnswers = 0
    private var hasAnsweredCurrent = false

    override fun onAttach(context: Context) {
        super.onAttach(context)
        listener = context as? Listener
    }

    override fun onDetach() {
        super.onDetach()
        listener = null
    }

    override fun onViewCreated(view: View, savedInstanceState: Bundle?) {
        val profile = WoofieRepository.profile ?: return
        questions = WoofieRepository.getQuestionsFor(profile.profession)

        val progressText: TextView = view.findViewById(R.id.textLessonProgress)
        val questionText: TextView = view.findViewById(R.id.textLessonQuestion)
        val resultText: TextView = view.findViewById(R.id.textLessonResult)
        val optionsGroup: RadioGroup = view.findViewById(R.id.optionsGroup)
        val optionOne: RadioButton = view.findViewById(R.id.optionOne)
        val optionTwo: RadioButton = view.findViewById(R.id.optionTwo)
        val optionThree: RadioButton = view.findViewById(R.id.optionThree)
        val buttonCheck: MaterialButton = view.findViewById(R.id.buttonCheck)
        val options = listOf(optionOne, optionTwo, optionThree)

        val optionAnim = AnimationUtils.loadAnimation(requireContext(), R.anim.woofie_option_pop)
        val resultAnim = AnimationUtils.loadAnimation(requireContext(), R.anim.woofie_result_fade_in)

        fun bindQuestion() {
            val question = questions[currentIndex]
            progressText.text = getString(R.string.lesson_progress, currentIndex + 1, questions.size)
            questionText.text = question.prompt
            optionOne.text = question.options[0]
            optionTwo.text = question.options[1]
            optionThree.text = question.options[2]
            optionsGroup.clearCheck()
            options.forEach { option ->
                option.isEnabled = true
                option.setBackgroundResource(R.drawable.lesson_option_selector)
            }
            resultText.text = ""
            buttonCheck.text = getString(R.string.lesson_check)
            hasAnsweredCurrent = false
        }

        fun showAnswerState(selectedIndex: Int, correctIndex: Int) {
            options.forEachIndexed { index, radioButton ->
                val background = when {
                    index == correctIndex -> R.drawable.lesson_option_correct
                    index == selectedIndex -> R.drawable.lesson_option_incorrect
                    else -> R.drawable.lesson_option_idle
                }
                radioButton.setBackgroundResource(background)
                radioButton.isEnabled = false
            }
        }

        optionsGroup.setOnCheckedChangeListener { group, checkedId ->
            if (checkedId == View.NO_ID || hasAnsweredCurrent) return@setOnCheckedChangeListener
            group.findViewById<RadioButton>(checkedId)?.startAnimation(optionAnim)
        }

        buttonCheck.setOnClickListener {
            if (buttonCheck.text == getString(R.string.lesson_next)) {
                currentIndex += 1
                if (currentIndex >= questions.size) {
                    listener?.onLessonFinished(correctAnswers, questions.size)
                } else {
                    bindQuestion()
                }
                return@setOnClickListener
            }

            val selectedId = optionsGroup.checkedRadioButtonId
            if (selectedId == View.NO_ID) {
                resultText.text = getString(R.string.lesson_select_option)
                resultText.startAnimation(resultAnim)
                return@setOnClickListener
            }

            val selectedIndex = when (selectedId) {
                R.id.optionOne -> 0
                R.id.optionTwo -> 1
                else -> 2
            }
            val currentQuestion = questions[currentIndex]
            val isCorrect = selectedIndex == currentQuestion.correctIndex
            if (isCorrect) correctAnswers += 1
            hasAnsweredCurrent = true
            showAnswerState(selectedIndex = selectedIndex, correctIndex = currentQuestion.correctIndex)

            resultText.text = if (isCorrect) {
                getString(R.string.lesson_correct)
            } else {
                getString(
                    R.string.lesson_incorrect,
                    currentQuestion.options[currentQuestion.correctIndex]
                )
            }
            resultText.startAnimation(resultAnim)
            buttonCheck.text = getString(R.string.lesson_next)
        }

        bindQuestion()
    }
}

package com.example.woofie.ui
import android.content.Context import android.os.Bundle import android.view.View import android.view.animation.AnimationUtils import android.widget.RadioButton import android.widget.RadioGroup import android.widget.TextView import androidx.fragment.app.Fragment import com.example.woofie.R import com.example.woofie.data.WoofieRepository import com.example.woofie.model.QuizQuestion import com.example.woofie.ui.common.applySystemBarsPadding import com.google.android.material.button.MaterialButton import com.google.android.material.card.MaterialCardView import com.google.android.material.progressindicator.LinearProgressIndicator
class LessonFragment : Fragment(R.layout.fragment_lesson) {
interface Listener { fun onLessonFinished(correctAnswers: Int, totalAnswers: Int) }
private var listener: Listener? = null private var questions: List<QuizQuestion> = emptyList() private var currentIndex = 0 private var correctAnswers = 0 private var hasAnsweredCurrent = false
override fun onAttach(context: Context) { super.onAttach(context) listener = context as? Listener }
override fun onDetach() { super.onDetach() listener = null }
override fun onViewCreated(view: View, savedInstanceState: Bundle?) { view.applySystemBarsPadding() val profile = WoofieRepository.profile ?: return questions = WoofieRepository.getQuestionsFor(profile.profession)
val progressText: TextView = view.findViewById(R.id.textLessonProgress) val progressBarId = resources.getIdentifier("lessonProgressBar", "id", requireContext().packageName) val progressBar: LinearProgressIndicator? = if (progressBarId != 0) view.findViewById(progressBarId) else null val questionText: TextView = view.findViewById(R.id.textLessonQuestion) val resultText: TextView = view.findViewById(R.id.textLessonResult) val wrongFeedbackCard: MaterialCardView = view.findViewById(R.id.cardWrongFeedback) val wrongFeedbackBody: TextView = view.findViewById(R.id.textWrongFeedbackBody) val wrongFeedbackHint: TextView = view.findViewById(R.id.textWrongFeedbackHint) val optionsGroup: RadioGroup = view.findViewById(R.id.optionsGroup) val optionOne: RadioButton = view.findViewById(R.id.optionOne) val optionTwo: RadioButton = view.findViewById(R.id.optionTwo) val optionThree: RadioButton = view.findViewById(R.id.optionThree) val buttonCheck: MaterialButton = view.findViewById(R.id.buttonCheck) val options = listOf(optionOne, optionTwo, optionThree)
val optionAnim = AnimationUtils.loadAnimation(requireContext(), R.anim.woofie_option_pop) val resultAnim = AnimationUtils.loadAnimation(requireContext(), R.anim.woofie_result_fade_in) val questionAnim = AnimationUtils.loadAnimation(requireContext(), R.anim.woofie_slide_up) val shakeAnim = AnimationUtils.loadAnimation(requireContext(), R.anim.woofie_shake) var isFeedbackExpanded = false
progressBar?.max = questions.size
fun animateOptionsEntry() { options.forEachIndexed { index, option -> option.alpha = 0f option.translationY = 16f option.animate() .alpha(1f) .translationY(0f) .setStartDelay((index * 70).toLong()) .setDuration(180) .start() } }
fun collapseFeedback() { isFeedbackExpanded = false wrongFeedbackBody.maxLines = 2 wrongFeedbackHint.text = getString(R.string.lesson_feedback_expand) }
fun hideFeedback() { wrongFeedbackCard.visibility = View.GONE collapseFeedback() }
fun showWrongFeedback(selectedOption: String, correctOption: String) { wrongFeedbackBody.text = getString( R.string.lesson_feedback_body, selectedOption, correctOption ) collapseFeedback() wrongFeedbackCard.visibility = View.VISIBLE wrongFeedbackCard.startAnimation(resultAnim) }
fun bindQuestion() { val question = questions[currentIndex] progressText.text = getString(R.string.lesson_progress, currentIndex + 1, questions.size) progressBar?.progress = currentIndex + 1 questionText.text = question.prompt questionText.startAnimation(questionAnim) optionOne.text = question.options[0] optionTwo.text = question.options[1] optionThree.text = question.options[2] optionsGroup.clearCheck() options.forEach { option -> option.isEnabled = true option.setBackgroundResource(R.drawable.lesson_option_selector) } resultText.text = "" hideFeedback() buttonCheck.text = getString(R.string.lesson_check) hasAnsweredCurrent = false animateOptionsEntry() }
fun showAnswerState(selectedIndex: Int, correctIndex: Int) { options.forEachIndexed { index, radioButton -> val background = when { index == correctIndex -> R.drawable.lesson_option_correct index == selectedIndex -> R.drawable.lesson_option_incorrect else -> R.drawable.lesson_option_idle } radioButton.setBackgroundResource(background) radioButton.isEnabled = false } }
optionsGroup.setOnCheckedChangeListener { group, checkedId -> if (checkedId == View.NO_ID || hasAnsweredCurrent) return@setOnCheckedChangeListener group.findViewById<RadioButton>(checkedId)?.startAnimation(optionAnim) }
wrongFeedbackCard.setOnClickListener { isFeedbackExpanded = !isFeedbackExpanded wrongFeedbackBody.maxLines = if (isFeedbackExpanded) Int.MAX_VALUE else 2 wrongFeedbackHint.text = getString( if (isFeedbackExpanded) R.string.lesson_feedback_collapse else R.string.lesson_feedback_expand ) }
buttonCheck.setOnClickListener { it.animate().scaleX(0.96f).scaleY(0.96f).setDuration(70) .withEndAction { it.animate().scaleX(1f).scaleY(1f).setDuration(90).start() }.start()
if (buttonCheck.text == getString(R.string.lesson_next)) { currentIndex += 1 if (currentIndex >= questions.size) { listener?.onLessonFinished(correctAnswers, questions.size) } else { bindQuestion() } return@setOnClickListener }
val selectedId = optionsGroup.checkedRadioButtonId if (selectedId == View.NO_ID) { resultText.text = getString(R.string.lesson_select_option) resultText.startAnimation(resultAnim) optionsGroup.startAnimation(shakeAnim) return@setOnClickListener }
val selectedIndex = when (selectedId) { R.id.optionOne -> 0 R.id.optionTwo -> 1 else -> 2 } val currentQuestion = questions[currentIndex] val isCorrect = selectedIndex == currentQuestion.correctIndex if (isCorrect) correctAnswers += 1 hasAnsweredCurrent = true showAnswerState(selectedIndex = selectedIndex, correctIndex = currentQuestion.correctIndex)
resultText.text = if (isCorrect) { hideFeedback() getString(R.string.lesson_correct) } else { showWrongFeedback( selectedOption = currentQuestion.options[selectedIndex], correctOption = currentQuestion.options[currentQuestion.correctIndex] ) getString( R.string.lesson_incorrect, currentQuestion.options[currentQuestion.correctIndex] ) } resultText.startAnimation(resultAnim) if (!isCorrect) { view.findViewById<RadioButton>(selectedId)?.startAnimation(shakeAnim) } buttonCheck.text = getString(R.string.lesson_next) }
bindQuestion() } }

package com.example.woofie.ui

import android.annotation.SuppressLint
import android.animation.ObjectAnimator
import android.animation.ValueAnimator
import android.content.Context
import android.os.Bundle
import android.view.MotionEvent
import android.view.LayoutInflater
import android.view.View
import android.view.animation.AnimationUtils
import android.widget.FrameLayout
import android.widget.LinearLayout
import android.widget.TextView
import androidx.core.content.ContextCompat
import androidx.fragment.app.Fragment
import com.example.woofie.R
import com.example.woofie.data.WoofieRepository
import com.example.woofie.ui.common.applySystemBarsPadding

class LessonPathFragment : Fragment(R.layout.fragment_lesson_path) {

    interface Listener {
        fun onOpenLessonFromPath()
    }

    private var listener: Listener? = null

    override fun onAttach(context: Context) {
        super.onAttach(context)
        listener = context as? Listener
    }

    override fun onDetach() {
        super.onDetach()
        listener = null
    }

    @SuppressLint("ClickableViewAccessibility")
    override fun onViewCreated(view: View, savedInstanceState: Bundle?) {
        view.applySystemBarsPadding()
        val profile = WoofieRepository.profile ?: return
        val container: LinearLayout = view.findViewById(R.id.pathContainer)
        val trailContainerId = resources.getIdentifier("pathTrailContainer", "id", requireContext().packageName)
        val trailContainer: LinearLayout? = if (trailContainerId != 0) view.findViewById(trailContainerId) else null
        val nodeAnim = AnimationUtils.loadAnimation(requireContext(), R.anim.woofie_option_pop)
        container.removeAllViews()
        trailContainer?.removeAllViews()

        val totalNodes = WoofieRepository.LESSON_SIZE
        val completed = profile.completedLessons.coerceAtMost(totalNodes)
        val nextUnlocked = (completed + 1).coerceAtMost(totalNodes)
        val currentNode = if (nextUnlocked <= totalNodes) nextUnlocked else totalNodes

        fun dp(value: Int): Int = (value * resources.displayMetrics.density).toInt()

        trailContainer?.let { trail ->
            repeat(totalNodes) { index ->
                val number = index + 1
                val isDone = number <= completed
                val isCurrentTrail = number == currentNode

                val chip = TextView(requireContext()).apply {
                    text = number.toString()
                    textSize = 13f
                    setTypeface(typeface, android.graphics.Typeface.BOLD)
                    gravity = android.view.Gravity.CENTER
                    layoutParams = LinearLayout.LayoutParams(dp(30), dp(30))
                    background = when {
                        isDone -> ContextCompat.getDrawable(requireContext(), R.drawable.lesson_node_completed)
                        isCurrentTrail -> ContextCompat.getDrawable(requireContext(), R.drawable.lesson_node_current)
                        else -> ContextCompat.getDrawable(requireContext(), R.drawable.lesson_node_locked)
                    }
                    setTextColor(
                        if (isDone) ContextCompat.getColor(requireContext(), R.color.woofie_text_on_dark)
                        else ContextCompat.getColor(requireContext(), R.color.woofie_primary_dark)
                    )
                }
                trail.addView(chip)

                if (number < totalNodes) {
                    val connector = View(requireContext()).apply {
                        layoutParams = LinearLayout.LayoutParams(dp(18), dp(4)).also { params ->
                            params.leftMargin = dp(6)
                            params.rightMargin = dp(6)
                        }
                        setBackgroundColor(
                            ContextCompat.getColor(
                                requireContext(),
                                if (number < currentNode) R.color.woofie_primary else R.color.woofie_gray_200
                            )
                        )
                    }
                    trail.addView(connector)
                }
            }
        }

        repeat(totalNodes) { index ->
            val nodeView = LayoutInflater.from(requireContext())
                .inflate(R.layout.item_lesson_path_node, container, false)

            val anchor: FrameLayout = nodeView.findViewById(R.id.nodeAnchor)
            val badge: TextView = nodeView.findViewById(R.id.textNodeBadge)
            val connector: View = nodeView.findViewById(R.id.pathConnector)
            val shadow: View = nodeView.findViewById(R.id.nodeShadow)

            val nodeNumber = index + 1
            val isCompleted = nodeNumber <= completed
            val isUnlocked = nodeNumber <= nextUnlocked
            val isCurrent = nodeNumber == currentNode

            badge.text = nodeNumber.toString()
            badge.background = when {
                isCompleted -> ContextCompat.getDrawable(requireContext(), R.drawable.lesson_node_completed)
                isCurrent -> ContextCompat.getDrawable(requireContext(), R.drawable.lesson_node_current)
                isUnlocked -> ContextCompat.getDrawable(requireContext(), R.drawable.lesson_node_unlocked)
                else -> ContextCompat.getDrawable(requireContext(), R.drawable.lesson_node_locked)
            }
            badge.setTextColor(
                if (isCompleted) ContextCompat.getColor(requireContext(), R.color.woofie_text_on_dark)
                else ContextCompat.getColor(requireContext(), R.color.woofie_primary_dark)
            )
            badge.alpha = if (isUnlocked) 1f else 0.65f
            badge.isEnabled = isUnlocked
            shadow.alpha = if (isUnlocked) 1f else 0.45f
            badge.scaleX = if (isCurrent) 1.08f else 1f
            badge.scaleY = if (isCurrent) 1.08f else 1f

            val anchorParams = anchor.layoutParams as LinearLayout.LayoutParams
            val offsetX = when (index % 6) {
                0 -> -120f
                1 -> -26f
                2 -> 86f
                3 -> 120f
                4 -> 18f
                else -> -92f
            }
            anchor.translationX = offsetX
            anchor.layoutParams = anchorParams

            connector.visibility = if (nodeNumber == totalNodes) View.GONE else View.VISIBLE
            if (nodeNumber < totalNodes) {
                val nextOffsetX = when ((index + 1) % 6) {
                    0 -> -120f
                    1 -> -26f
                    2 -> 86f
                    3 -> 120f
                    4 -> 18f
                    else -> -92f
                }
                connector.translationX = (nextOffsetX - offsetX) / 2f
                connector.rotation = (nextOffsetX - offsetX) / 10f
            }

            if (isUnlocked) {
                val floatAnim = ObjectAnimator.ofFloat(badge, View.TRANSLATION_Y, 0f, -8f, 0f).apply {
                    duration = 1800
                    startDelay = index * 100L
                    repeatCount = ValueAnimator.INFINITE
                }
                floatAnim.start()

                badge.setOnTouchListener { touchedView, event ->
                    when (event.actionMasked) {
                        MotionEvent.ACTION_DOWN -> {
                            touchedView.animate().scaleX(0.92f).scaleY(0.92f).setDuration(80).start()
                            true
                        }

                        MotionEvent.ACTION_UP -> {
                            touchedView.animate().scaleX(1f).scaleY(1f).setDuration(120).start()
                            touchedView.performClick()
                            true
                        }

                        MotionEvent.ACTION_CANCEL -> {
                            touchedView.animate().scaleX(1f).scaleY(1f).setDuration(120).start()
                            true
                        }

                        else -> false
                    }
                }

                badge.setOnClickListener {
                    it.startAnimation(nodeAnim)
                    listener?.onOpenLessonFromPath()
                }
            }

            badge.elevation = if (isCurrent) 10f else 6f

            nodeView.startAnimation(nodeAnim)
            container.addView(nodeView)
        }
    }
}

package com.example.woofie.ui

import android.content.Context
import android.os.Bundle
import android.view.View
import android.widget.TextView
import androidx.fragment.app.Fragment
import com.example.woofie.R
import com.example.woofie.model.Profession
import com.google.android.material.button.MaterialButton
import com.google.android.material.chip.Chip
import com.google.android.material.chip.ChipGroup

class OnboardingFragment : Fragment(R.layout.fragment_onboarding) {

    interface Listener {
        fun onOnboardingCompleted(profession: Profession, level: String)
    }

    private var listener: Listener? = null

    override fun onAttach(context: Context) {
        super.onAttach(context)
        listener = context as? Listener
    }

    override fun onDetach() {
        super.onDetach()
        listener = null
    }

    override fun onViewCreated(view: View, savedInstanceState: Bundle?) {
        val buttonContinue: MaterialButton = view.findViewById(R.id.buttonContinue)
        val feedbackText: TextView = view.findViewById(R.id.textSelectionSummary)
        val chipProfessionGroup: ChipGroup = view.findViewById(R.id.chipProfessionGroup)
        val chipLevelGroup: ChipGroup = view.findViewById(R.id.chipLevelGroup)

        val chipsByProfession = mapOf(
            R.id.chipProfessionIt to Profession.IT,
            R.id.chipProfessionHealth to Profession.HEALTH,
            R.id.chipProfessionSales to Profession.SALES
        )

        fun selectedProfession(): Profession? = chipsByProfession[chipProfessionGroup.checkedChipId]

        fun selectedLevel(): String? {
            val selectedChipId = chipLevelGroup.checkedChipId
            if (selectedChipId == View.NO_ID) return null
            val chip = view.findViewById<Chip>(selectedChipId)
            return chip.text.toString()
        }

        fun refreshContinueState() {
            val profession = selectedProfession()
            val level = selectedLevel()
            val enabled = profession != null && level != null
            buttonContinue.isEnabled = enabled

            feedbackText.text = if (profession != null && level != null) {
                getString(
                    R.string.onboarding_summary,
                    profession.displayName,
                    level
                )
            } else {
                getString(R.string.onboarding_summary_empty)
            }
        }

        chipProfessionGroup.setOnCheckedStateChangeListener { _, _ -> refreshContinueState() }
        chipLevelGroup.setOnCheckedStateChangeListener { _, _ -> refreshContinueState() }

        buttonContinue.setOnClickListener {
            val profession = selectedProfession() ?: return@setOnClickListener
            val level = selectedLevel() ?: return@setOnClickListener
            listener?.onOnboardingCompleted(profession, level)
        }

        refreshContinueState()
    }
}

